using System.ComponentModel;
using System.Text;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Logging;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "";
var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.Error.WriteLine("Set the OPENAI_API_KEY environment variable to run the agent.");
    return 1;
}

var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------
var notebook = new Notebook();
var webSearch = new WebSearcher();

var tools = new AITool[]
{
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(webSearch.FetchPageAsync),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

// ---------------------------------------------------------------------------
// Build the agent chat client
// ---------------------------------------------------------------------------
using var loggerFactory = LoggerFactory.Create(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));

IChatClient innerClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

IChatClient agent = new ChatClientBuilder(innerClient)
    .UseFunctionInvocation(loggerFactory, configure: fic =>
    {
        fic.MaximumIterationsPerRequest = 15;
    })
    .Build();

// ---------------------------------------------------------------------------
// Run the agent
// ---------------------------------------------------------------------------
var systemPrompt = """
    You are a research agent. Your goal is to thoroughly research the topic the user
    gives you by searching the web, reading relevant pages, and taking notes on key
    findings.

    Follow this workflow:
    1. Start by searching the web for the topic.
    2. Pick the most relevant results and fetch their content.
    3. Take notes on important facts, data, and insights you find.
    4. If needed, do additional searches to fill gaps.
    5. Once you have enough material, retrieve your notes and write a clear,
       well-structured summary with the key findings.

    Always cite the URLs where you found information.
    """;

var messages = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
    new(ChatRole.User, $"Research the following topic and provide a summary: {topic}"),
};

var options = new ChatOptions { Tools = tools };

Console.WriteLine("Agent is working...\n");

var response = await agent.GetResponseAsync(messages, options);

Console.WriteLine("═══════════════════════════════════════════════════════════════");
Console.WriteLine("  RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════════════════════════════\n");
Console.WriteLine(response.Text);
Console.WriteLine("\n═══════════════════════════════════════════════════════════════");
Console.WriteLine($"  Notes collected: {notebook.Count}");
Console.WriteLine("═══════════════════════════════════════════════════════════════\n");

return 0;

// ---------------------------------------------------------------------------
// Helper
// ---------------------------------------------------------------------------
static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var input = Console.ReadLine()?.Trim();
    if (string.IsNullOrWhiteSpace(input))
    {
        Console.Error.WriteLine("No topic provided.");
        Environment.Exit(1);
    }
    return input;
}

// ============================================================================
// Web Search Tool
// ============================================================================
sealed class WebSearcher
{
    private static readonly HttpClient Http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
            { "Accept", "text/html,application/xhtml+xml" },
        },
    };

    [Description("Search the web for a query. Returns a list of result titles and URLs.")]
    public async Task<string> SearchAsync(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");
        try
        {
            // Use DuckDuckGo HTML search (no API key required)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await Http.GetStringAsync(url);
            return ParseDuckDuckGoResults(html);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch the text content of a web page given its URL.")]
    public async Task<string> FetchPageAsync(
        [Description("The URL to fetch")] string url)
    {
        Console.WriteLine($"  📄 Fetching: {url}");
        try
        {
            var html = await Http.GetStringAsync(url);
            var text = StripHtml(html);
            // Truncate to avoid blowing up context
            return text.Length > 8_000 ? text[..8_000] + "\n...(truncated)" : text;
        }
        catch (Exception ex)
        {
            return $"Fetch failed: {ex.Message}";
        }
    }

    private static string ParseDuckDuckGoResults(string html)
    {
        var sb = new StringBuilder();
        var results = 0;

        // Extract result links: <a rel="nofollow" class="result__a" href="...">Title</a>
        var marker = "class=\"result__a\"";
        var idx = 0;
        while (results < 8 && (idx = html.IndexOf(marker, idx, StringComparison.Ordinal)) >= 0)
        {
            // Find href
            var hrefStart = html.IndexOf("href=\"", idx, StringComparison.Ordinal);
            if (hrefStart < 0) break;
            hrefStart += 6;
            var hrefEnd = html.IndexOf('"', hrefStart);
            if (hrefEnd < 0) break;
            var href = html[hrefStart..hrefEnd];

            // Find title text between > and </a>
            var titleStart = html.IndexOf('>', hrefEnd);
            if (titleStart < 0) break;
            titleStart++;
            var titleEnd = html.IndexOf("</a>", titleStart, StringComparison.Ordinal);
            if (titleEnd < 0) break;
            var title = StripHtml(html[titleStart..titleEnd]).Trim();

            if (!string.IsNullOrEmpty(title) && href.StartsWith("http", StringComparison.OrdinalIgnoreCase))
            {
                results++;
                sb.AppendLine($"{results}. {title}");
                sb.AppendLine($"   URL: {href}");
            }
            idx = titleEnd;
        }

        return results > 0
            ? $"Search results:\n{sb}"
            : "No results found.";
    }

    private static string StripHtml(string html)
    {
        // Remove script/style blocks, then tags, decode common entities
        var text = System.Text.RegularExpressions.Regex.Replace(
            html, @"<(script|style)[^>]*>.*?</\1>", "", System.Text.RegularExpressions.RegexOptions.Singleline);
        text = System.Text.RegularExpressions.Regex.Replace(text, @"<[^>]+>", " ");
        text = text.Replace("&amp;", "&").Replace("&lt;", "<").Replace("&gt;", ">")
                    .Replace("&quot;", "\"").Replace("&#39;", "'").Replace("&nbsp;", " ");
        text = System.Text.RegularExpressions.Regex.Replace(text, @"\s+", " ");
        return text.Trim();
    }
}

// ============================================================================
// Note-Taking Tool
// ============================================================================
sealed class Notebook
{
    private readonly List<string> _notes = [];
    private readonly object _lock = new();

    public int Count
    {
        get { lock (_lock) return _notes.Count; }
    }

    [Description("Save a research note. Use this to record important facts and findings along with the source URL.")]
    public string AddNote(
        [Description("The note text to save, including source URL")] string note)
    {
        lock (_lock)
        {
            _notes.Add(note);
            Console.WriteLine($"  📝 Note #{_notes.Count} saved");
            return $"Note #{_notes.Count} saved successfully.";
        }
    }

    [Description("Retrieve all saved research notes collected so far.")]
    public string GetNotes()
    {
        lock (_lock)
        {
            if (_notes.Count == 0)
                return "No notes saved yet.";

            var sb = new StringBuilder();
            for (var i = 0; i < _notes.Count; i++)
                sb.AppendLine($"--- Note #{i + 1} ---\n{_notes[i]}\n");
            return sb.ToString();
        }
    }
}

