    public string AddNote(
        [Description("The note text to save, including source URL")] string note)
    {
        lock (_lock)
        {
            _notes.Add(note);
            Console.WriteLine($"  📝 Note #{_notes.Count} saved");
            return $"Note #{_notes.Count} saved successfully.";
        }
    }

